('falling-wedge', 'Falling Wedge Pattern', 'Bullish reversal pattern with converging downward-sloping trendlines.', 'The falling wedge is a bullish reversal pattern where price makes lower lows and lower highs but selling pressure diminishes, leading to breakout.', 'Chart Patterns', 'intermediate', 12, ARRAY['wedge', 'reversal', 'bullish', 'momentum'], 'published', NOW()),
('bullish-flag', 'Bullish Flag Pattern', 'Short-term continuation pattern after a strong upward move.', 'The bullish flag forms after a sharp rally, featuring a small rectangular consolidation that slopes against the trend before continuation.', 'Chart Patterns', 'beginner', 8, ARRAY['flag', 'continuation', 'bullish', 'momentum'], 'published', NOW()),
('bearish-flag', 'Bearish Flag Pattern', 'Short-term continuation pattern after a strong downward move.', 'The bearish flag forms after a sharp decline, featuring a small upward-sloping consolidation before the downtrend resumes.', 'Chart Patterns', 'beginner', 8, ARRAY['flag', 'continuation', 'bearish', 'momentum'], 'published', NOW()),
('bullish-pennant', 'Bullish Pennant Pattern', 'Continuation pattern with converging trendlines after an uptrend.', 'The bullish pennant is a continuation pattern that forms after a strong upward move, characterized by converging trendlines and decreasing volume.', 'Chart Patterns', 'beginner', 9, ARRAY['pennant', 'continuation', 'bullish', 'consolidation'], 'published', NOW()),
('bearish-pennant', 'Bearish Pennant Pattern', 'Continuation pattern with converging trendlines after a downtrend.', 'The bearish pennant forms after a sharp decline, with price consolidating in a small symmetrical triangle before continuing lower.', 'Chart Patterns', 'beginner', 9, ARRAY['pennant', 'continuation', 'bearish', 'consolidation'], 'published', NOW()),
('inverse-head-shoulders', 'Inverse Head and Shoulders', 'Bullish reversal pattern signaling end of a downtrend.', 'The inverse head and shoulders is the bullish counterpart of the H&S pattern, marking potential trend reversal from bearish to bullish.', 'Chart Patterns', 'intermediate', 14, ARRAY['reversal', 'bullish', 'head-shoulders', 'bottom'], 'published', NOW()),
('triple-top', 'Triple Top Pattern', 'Strong bearish reversal with three failed attempts at resistance.', 'The triple top is a bearish reversal pattern where price tests the same resistance level three times before breaking down.', 'Chart Patterns', 'intermediate', 11, ARRAY['reversal', 'bearish', 'resistance', 'distribution'], 'published', NOW()),
('triple-bottom', 'Triple Bottom Pattern', 'Strong bullish reversal with three failed breakdown attempts.', 'The triple bottom is a bullish reversal pattern where price tests the same support level three times before breaking out.', 'Chart Patterns', 'intermediate', 11, ARRAY['reversal', 'bullish', 'support', 'accumulation'], 'published', NOW()),
