-- Technical Indicators (15 articles)
('stochastic-oscillator', 'Stochastic Oscillator Guide', 'Momentum indicator comparing closing price to price range.', 'The stochastic oscillator measures momentum by comparing the closing price to the price range over a specified period, identifying overbought and oversold conditions.', 'Technical Indicators', 'intermediate', 13, ARRAY['stochastic', 'momentum', 'overbought', 'oversold'], 'published', NOW()),
